<!DOCTYPE html>
<html lang="fr">
<head>
    <meta charset="UTF-8"/>
    <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
    <title>ENT — Portail Numérique | GSJLF</title>
    <link href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;0,700;1,400;1,600&family=Outfit:wght@300;400;500;600&display=swap" rel="stylesheet"/>
    <style>
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
        :root{
            --green:#113B26;--green2:#1a5238;--green3:#2e7d52;
            --brown:#864C20;--beige:#F5ECD7;
            --ctd:#2E7D32;--ctd2:#43A047;
            --gold:#C9A84C;--gold2:#e8c56a;
            --cream:#FDFCF8;--ink:#0D1F15;--muted:#6B7C72;
            --ease:cubic-bezier(.22,1,.36,1);
        }
        html{scroll-behavior:smooth}
        body{font-family:'Outfit',sans-serif;background:var(--cream);color:var(--ink);overflow-x:hidden}

        /* CURSOR */
        .cursor{position:fixed;width:10px;height:10px;background:var(--gold);border-radius:50%;pointer-events:none;z-index:9999;transform:translate(-50%,-50%);mix-blend-mode:multiply;transition:width .3s,height .3s}
        .cursor-ring{position:fixed;width:36px;height:36px;border:1.5px solid rgba(201,168,76,.4);border-radius:50%;pointer-events:none;z-index:9998;transform:translate(-50%,-50%);transition:left .15s var(--ease),top .15s var(--ease)}

        /* NAV */
        nav{position:fixed;top:0;left:0;right:0;z-index:100;padding:22px 64px;display:flex;align-items:center;justify-content:space-between;transition:all .4s var(--ease)}
        nav.scrolled{background:rgba(13,31,21,.94);backdrop-filter:blur(20px);padding:14px 64px;border-bottom:1px solid rgba(255,255,255,.06)}
        .nav-brand{display:flex;align-items:center;gap:14px}
        .nav-logo{width:48px;height:48px;border-radius:50%;overflow:hidden;border:2px solid rgba(201,168,76,.4);box-shadow:0 4px 16px rgba(0,0,0,.3);flex-shrink:0}
        .nav-logo img{width:100%;height:100%;object-fit:cover}
        .nav-wordmark h1{font-family:'Cormorant Garamond',serif;font-size:15px;color:#fff;font-weight:600;line-height:1.2}
        .nav-wordmark span{font-size:10px;color:rgba(255,255,255,.4);letter-spacing:.14em;text-transform:uppercase}
        .nav-links{display:flex;align-items:center;gap:32px}
        .nav-links a{font-size:13px;color:rgba(255,255,255,.6);text-decoration:none;letter-spacing:.04em;transition:color .25s;position:relative}
        .nav-links a::after{content:'';position:absolute;bottom:-3px;left:0;width:0;height:1px;background:var(--gold);transition:width .3s var(--ease)}
        .nav-links a:hover{color:#fff}
        .nav-links a:hover::after{width:100%}
        .nav-cta{display:flex;align-items:center;gap:8px;padding:10px 22px;border-radius:100px;background:rgba(201,168,76,.15);border:1px solid rgba(201,168,76,.3);color:var(--gold2);font-size:13px;font-weight:500;text-decoration:none;transition:all .3s var(--ease);letter-spacing:.04em}
        .nav-cta:hover{background:var(--gold);color:var(--ink)}
        .nav-cta svg{width:14px;height:14px}

        /* ══════════════ HERO ══════════════ */
        .hero{
            position:relative;min-height:100vh;overflow:hidden;
            display:flex;flex-direction:column;
        }

        /* Background split panels */
        .hero-bg{
            position:absolute;inset:0;display:grid;
            grid-template-columns:1fr 1fr 1fr;
            z-index:0;
        }
        .hero-bg-panel{
            position:relative;overflow:hidden;
        }
        .hero-bg-panel img{
            width:100%;height:100%;object-fit:cover;
            transition:transform 8s ease;
            filter:brightness(.28) saturate(.8);
        }
        .hero-bg-panel:hover img{transform:scale(1.04)}

        /* Vertical dividers */
        .hero-bg-panel::after{
            content:'';position:absolute;right:0;top:0;bottom:0;
            width:1px;background:rgba(255,255,255,.08);z-index:2;
        }
        .hero-bg-panel:last-child::after{display:none}

        /* Gradient overlay on top of panels */
        .hero-overlay{
            position:absolute;inset:0;z-index:1;
            background:
                    linear-gradient(180deg,rgba(13,31,21,.7) 0%,rgba(13,31,21,.2) 40%,rgba(13,31,21,.55) 100%),
                    linear-gradient(90deg,rgba(17,59,38,.5) 0%,transparent 40%,transparent 60%,rgba(17,59,38,.3) 100%);
        }

        /* Panel color tints */
        .hero-bg-panel.p-uahb{background:var(--green)}
        .hero-bg-panel.p-cmjlf{background:var(--brown)}
        .hero-bg-panel.p-ctd{background:var(--ctd)}
        .hero-bg-panel.p-uahb img{filter:brightness(.32) saturate(.7) hue-rotate(0deg)}
        .hero-bg-panel.p-cmjlf img{filter:brightness(.30) saturate(.6) sepia(.2)}
        .hero-bg-panel.p-ctd img{filter:brightness(.30) saturate(.8)}

        /* Noise grain */
        .hero::after{
            content:'';position:absolute;inset:0;z-index:2;pointer-events:none;
            background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.035'/%3E%3C/svg%3E");
            opacity:.6;mix-blend-mode:overlay;
        }

        /* Orbiting rings */
        .orbit-wrap{position:absolute;width:800px;height:800px;left:50%;top:50%;transform:translate(-50%,-50%);z-index:2;pointer-events:none}
        .orbit{position:absolute;border-radius:50%;border:1px solid rgba(255,255,255,.04);top:50%;left:50%;transform:translate(-50%,-50%)}
        .orbit.o1{width:280px;height:280px;animation:spin 45s linear infinite}
        .orbit.o2{width:500px;height:500px;animation:spin 70s linear infinite reverse}
        .orbit.o3{width:720px;height:720px;animation:spin 90s linear infinite}
        .orbit-dot{position:absolute;border-radius:50%;top:0;left:50%;transform:translate(-50%,-50%)}
        .o1 .orbit-dot{width:7px;height:7px;background:var(--gold);box-shadow:0 0 14px var(--gold)}
        .o2 .orbit-dot{width:5px;height:5px;background:rgba(255,255,255,.5);box-shadow:0 0 8px rgba(255,255,255,.4)}
        .o3 .orbit-dot{width:6px;height:6px;background:var(--ctd2);box-shadow:0 0 10px var(--ctd2)}
        @keyframes spin{to{transform:translate(-50%,-50%) rotate(360deg)}}

        /* Hero CONTENT */
        .hero-content{
            position:relative;z-index:3;
            display:flex;flex-direction:column;align-items:center;justify-content:center;
            min-height:100vh;padding:130px 60px 80px;text-align:center;
        }

        .hero-emblem{
            width:88px;height:88px;border-radius:50%;
            border:2px solid rgba(201,168,76,.35);
            box-shadow:0 0 0 8px rgba(201,168,76,.06),0 16px 48px rgba(0,0,0,.4);
            overflow:hidden;margin:0 auto 36px;
            animation:fadeUp .8s .1s var(--ease) both;
        }
        .hero-emblem img{width:100%;height:100%;object-fit:cover;background:#fff}

        .hero-badge{
            display:inline-flex;align-items:center;gap:10px;
            background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);
            border-radius:100px;padding:7px 18px;
            font-size:10px;letter-spacing:.16em;text-transform:uppercase;color:rgba(255,255,255,.55);
            margin-bottom:32px;animation:fadeUp .8s .25s var(--ease) both;
        }
        .hero-badge .bdot{width:6px;height:6px;border-radius:50%;background:var(--gold);box-shadow:0 0 8px var(--gold);animation:pulse 2s ease-in-out infinite}
        @keyframes pulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.4;transform:scale(.7)}}

        .hero-title{
            font-family:'Cormorant Garamond',serif;
            font-size:clamp(50px,6.5vw,84px);
            color:#fff;font-weight:700;line-height:1.02;
            margin-bottom:24px;
            animation:fadeUp .8s .4s var(--ease) both;
        }
        .hero-title em{font-style:italic;color:var(--gold2)}
        .hero-title .sub{
            display:block;
            font-size:clamp(22px,3vw,38px);
            color:rgba(255,255,255,.45);
            font-weight:300;margin-top:8px;
        }

        .hero-desc{
            font-size:15px;color:rgba(255,255,255,.45);line-height:1.85;
            max-width:520px;margin:0 auto 52px;
            animation:fadeUp .8s .55s var(--ease) both;
        }

        /* Entity pills in hero */
        .hero-entities{
            display:flex;align-items:center;gap:10px;flex-wrap:wrap;justify-content:center;
            margin-bottom:52px;
            animation:fadeUp .8s .65s var(--ease) both;
        }
        .entity-pill{
            display:flex;align-items:center;gap:8px;
            padding:8px 16px;border-radius:100px;
            backdrop-filter:blur(10px);
            font-size:11px;font-weight:500;letter-spacing:.06em;text-decoration:none;
            transition:all .3s var(--ease);
        }
        .entity-pill.uahb{background:rgba(17,59,38,.5);border:1px solid rgba(17,59,38,.8);color:rgba(255,255,255,.8)}
        .entity-pill.cmjlf{background:rgba(134,76,32,.5);border:1px solid rgba(134,76,32,.8);color:rgba(255,255,255,.8)}
        .entity-pill.ctd{background:rgba(46,125,50,.5);border:1px solid rgba(46,125,50,.8);color:rgba(255,255,255,.8)}
        .entity-pill:hover{transform:translateY(-2px);filter:brightness(1.2)}
        .entity-pill .epill-dot{width:7px;height:7px;border-radius:50%}
        .uahb .epill-dot{background:#6fcf97}
        .cmjlf .epill-dot{background:#e8a06e}
        .ctd .epill-dot{background:#81c784}

        .hero-actions{
            display:flex;align-items:center;justify-content:center;gap:14px;flex-wrap:wrap;
            animation:fadeUp .8s .75s var(--ease) both;
        }
        .btn-hp{
            display:inline-flex;align-items:center;gap:12px;
            padding:16px 38px;border-radius:100px;
            font-family:'Outfit',sans-serif;font-size:14px;font-weight:600;
            letter-spacing:.04em;text-decoration:none;cursor:pointer;border:none;
            transition:all .35s var(--ease);position:relative;overflow:hidden;
        }
        .btn-hp::before{
            content:'';position:absolute;inset:0;
            background:linear-gradient(90deg,transparent,rgba(255,255,255,.12),transparent);
            transform:translateX(-100%);transition:transform .7s;
        }
        .btn-hp:hover::before{transform:translateX(100%)}
        .btn-hp svg{width:16px;height:16px;flex-shrink:0}
        .btn-hp.primary{
            background:linear-gradient(135deg,var(--gold),var(--gold2));
            color:var(--ink);box-shadow:0 8px 32px rgba(201,168,76,.35);
        }
        .btn-hp.primary:hover{transform:translateY(-3px);box-shadow:0 18px 52px rgba(201,168,76,.45)}
        .btn-hp.ghost{
            background:rgba(255,255,255,.07);
            border:1px solid rgba(255,255,255,.15);
            color:rgba(255,255,255,.8);
        }
        .btn-hp.ghost:hover{background:rgba(255,255,255,.13);color:#fff;transform:translateY(-2px)}

        /* Panel labels at bottom */
        .hero-panel-labels{
            position:absolute;bottom:0;left:0;right:0;z-index:3;
            display:grid;grid-template-columns:1fr 1fr 1fr;
            pointer-events:none;
        }
        .hpl{
            padding:18px 28px;
            border-top:1px solid rgba(255,255,255,.07);
            display:flex;align-items:center;gap:10px;
        }
        .hpl-dot{width:8px;height:8px;border-radius:50%;flex-shrink:0}
        .hpl.uahb .hpl-dot{background:#6fcf97}
        .hpl.cmjlf .hpl-dot{background:#e8a06e}
        .hpl.ctd .hpl-dot{background:#81c784}
        .hpl-name{font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.4)}

        /* Scroll */
        .scroll-hint{
            position:absolute;bottom:44px;left:50%;transform:translateX(-50%);
            z-index:4;display:flex;flex-direction:column;align-items:center;gap:10px;
            animation:fadeUp .8s 1.1s var(--ease) both;
        }
        .scroll-hint span{font-size:9px;letter-spacing:.18em;text-transform:uppercase;color:rgba(255,255,255,.25)}
        .scroll-line{width:1px;height:44px;background:linear-gradient(to bottom,rgba(255,255,255,.15),transparent);overflow:hidden;position:relative}
        .scroll-line::after{content:'';position:absolute;top:-100%;left:0;width:100%;height:100%;background:linear-gradient(to bottom,transparent,var(--gold));animation:sa 2s ease-in-out infinite}
        @keyframes sa{0%{top:-100%}100%{top:200%}}

        /* ══════════════ STATS ══════════════ */
        .stats-band{
            background:#fff;display:grid;grid-template-columns:repeat(4,1fr);
            border-bottom:1px solid #f0f0f0;
        }
        .stat-item{
            padding:48px 36px;text-align:center;
            position:relative;border-right:1px solid #f0f0f0;
            transition:background .3s;
        }
        .stat-item:last-child{border-right:none}
        .stat-item:hover{background:#fafaf7}
        .stat-num{
            font-family:'Cormorant Garamond',serif;
            font-size:60px;font-weight:700;color:var(--green);
            line-height:1;margin-bottom:6px;
        }
        .stat-num sup{font-size:28px;color:var(--gold)}
        .stat-lbl{font-size:12px;color:var(--muted);letter-spacing:.08em;text-transform:uppercase}

        /* ══════════════ ENTITIES CARDS ══════════════ */
        .entities-section{padding:100px 64px;background:var(--cream)}
        .sec-label{display:inline-flex;align-items:center;gap:12px;font-size:10px;letter-spacing:.16em;text-transform:uppercase;color:var(--muted);margin-bottom:14px}
        .sec-label::before{content:'';width:28px;height:1px;background:var(--muted)}
        .sec-title{font-family:'Cormorant Garamond',serif;font-size:clamp(34px,4.5vw,54px);color:var(--ink);font-weight:700;line-height:1.1;margin-bottom:64px}
        .sec-title em{font-style:italic;color:var(--green)}

        .ent-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}

        .ent-card{
            border-radius:22px;overflow:hidden;position:relative;cursor:pointer;
            transition:transform .5s var(--ease),box-shadow .5s var(--ease);
            box-shadow:0 4px 24px rgba(0,0,0,.08);
        }
        .ent-card:hover{transform:translateY(-10px);box-shadow:0 32px 80px rgba(0,0,0,.16)}

        .ent-img-wrap{
            height:240px;overflow:hidden;position:relative;
        }
        .ent-img-wrap img{
            width:100%;height:100%;object-fit:cover;
            transition:transform .7s var(--ease),filter .4s;
            filter:brightness(.85) saturate(.9);
        }
        .ent-card:hover .ent-img-wrap img{transform:scale(1.06);filter:brightness(.9) saturate(1.05)}

        .ent-img-overlay{
            position:absolute;inset:0;
            background:linear-gradient(to top,rgba(13,31,21,.65) 0%,transparent 60%);
        }
        .ent-img-overlay.brown{background:linear-gradient(to top,rgba(86,48,21,.65) 0%,transparent 60%)}
        .ent-img-overlay.ctd{background:linear-gradient(to top,rgba(27,94,32,.65) 0%,transparent 60%)}

        .ent-badge{
            position:absolute;top:18px;left:18px;
            width:44px;height:44px;border-radius:12px;
            display:flex;align-items:center;justify-content:center;
            font-family:'Cormorant Garamond',serif;font-size:14px;font-weight:700;color:#fff;
            backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,.2);
            box-shadow:0 4px 12px rgba(0,0,0,.2);
        }
        .uahb-card .ent-badge{background:rgba(17,59,38,.6)}
        .cmjlf-card .ent-badge{background:rgba(134,76,32,.6)}
        .ctd-card .ent-badge{background:rgba(46,125,50,.6)}

        .ent-body{
            background:#fff;padding:28px;
            position:relative;
        }
        .ent-accent{width:32px;height:3px;border-radius:2px;margin-bottom:14px;transition:width .4s var(--ease)}
        .ent-card:hover .ent-accent{width:52px}
        .uahb-card .ent-accent{background:var(--green)}
        .cmjlf-card .ent-accent{background:var(--brown)}
        .ctd-card .ent-accent{background:var(--ctd)}

        .ent-body h3{font-family:'Cormorant Garamond',serif;font-size:22px;font-weight:700;color:var(--ink);line-height:1.2;margin-bottom:8px}
        .ent-body p{font-size:13px;color:var(--muted);line-height:1.65;margin-bottom:20px}
        .ent-link{
            display:inline-flex;align-items:center;gap:8px;
            font-size:12px;font-weight:600;letter-spacing:.08em;text-transform:uppercase;
            text-decoration:none;transition:gap .3s var(--ease);
        }
        .uahb-card .ent-link{color:var(--green)}
        .cmjlf-card .ent-link{color:var(--brown)}
        .ctd-card .ent-link{color:var(--ctd)}
        .ent-card:hover .ent-link{gap:14px}
        .ent-link svg{width:14px;height:14px}

        /* ══════════════ AUTH SPLIT SECTION ══════════════ */
        .auth-section{
            display:grid;grid-template-columns:1fr 1fr;
            min-height:680px;overflow:hidden;
        }

        /* Left — Sign in */
        .auth-signin{
            position:relative;overflow:hidden;
            display:flex;flex-direction:column;justify-content:flex-end;
            padding:56px;
        }
        .auth-signin-bg{
            position:absolute;inset:0;
            background-image:url('data:image/jpeg;base64,');
            background-size:cover;background-position:center;
            filter:brightness(.28) saturate(.7);
            transition:transform 8s ease,filter .4s;
        }
        .auth-signin:hover .auth-signin-bg{transform:scale(1.04);filter:brightness(.34) saturate(.8)}
        .auth-signin::after{
            content:'';position:absolute;inset:0;
            background:linear-gradient(160deg,rgba(17,59,38,.4) 0%,rgba(13,31,21,.9) 80%);
        }
        .auth-signin-content{position:relative;z-index:2}
        .auth-tag{
            display:inline-flex;align-items:center;gap:8px;
            background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.12);
            border-radius:100px;padding:6px 14px;
            font-size:10px;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,.6);
            margin-bottom:20px;
        }
        .auth-signin-content h2{font-family:'Cormorant Garamond',serif;font-size:42px;color:#fff;font-weight:700;line-height:1.1;margin-bottom:14px}
        .auth-signin-content h2 em{font-style:italic;color:var(--gold2)}
        .auth-signin-content p{font-size:14px;color:rgba(255,255,255,.5);line-height:1.7;max-width:340px;margin-bottom:32px}
        .auth-btn-white{
            display:inline-flex;align-items:center;gap:12px;
            padding:14px 32px;border-radius:100px;
            background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.2);
            color:#fff;font-size:13px;font-weight:500;text-decoration:none;
            transition:all .3s var(--ease);backdrop-filter:blur(8px);
            width:fit-content;
        }
        .auth-btn-white:hover{background:rgba(255,255,255,.18);transform:translateX(4px)}
        .auth-btn-white.gold-btn{
            background:linear-gradient(135deg,var(--gold),var(--gold2));
            color:var(--ink);font-weight:600;border:none;
            box-shadow:0 8px 24px rgba(201,168,76,.3);
        }
        .auth-btn-white.gold-btn:hover{box-shadow:0 14px 36px rgba(201,168,76,.4);transform:translateY(-2px)}
        .auth-btn-white svg{width:15px;height:15px}

        /* Right — Sign up */
        .auth-register{
            position:relative;overflow:hidden;
            display:flex;flex-direction:column;justify-content:flex-end;
            padding:56px;
            background:var(--beige);
        }
        .auth-reg-bg{
            position:absolute;inset:0;
            background-image:url('data:image/jpeg;base64,');
            background-size:cover;background-position:center top;
            filter:brightness(.3) saturate(.6) sepia(.15);
            transition:transform 8s ease,filter .4s;
        }
        .auth-register:hover .auth-reg-bg{transform:scale(1.04);filter:brightness(.36) saturate(.7) sepia(.1)}
        .auth-register::after{
            content:'';position:absolute;inset:0;
            background:linear-gradient(160deg,rgba(134,76,32,.35) 0%,rgba(86,48,21,.92) 80%);
        }
        .auth-reg-content{position:relative;z-index:2}
        .auth-reg-content h2{font-family:'Cormorant Garamond',serif;font-size:42px;color:#fff;font-weight:700;line-height:1.1;margin-bottom:14px}
        .auth-reg-content h2 em{font-style:italic;color:var(--gold2)}
        .auth-reg-content p{font-size:14px;color:rgba(255,255,255,.5);line-height:1.7;max-width:340px;margin-bottom:32px}
        .auth-reg-tag{
            background:rgba(134,76,32,.35);border-color:rgba(134,76,32,.5);color:rgba(255,255,255,.6);
        }

        /* ══════════════ FEATURES ══════════════ */
        .features-section{
            background:var(--green);padding:100px 64px;position:relative;overflow:hidden;
        }
        .features-section::before{
            content:'';position:absolute;inset:0;
            background:
                    radial-gradient(ellipse 70% 60% at 100% 30%,rgba(46,125,82,.4) 0%,transparent 60%),
                    radial-gradient(ellipse 50% 50% at 0% 80%,rgba(201,168,76,.08) 0%,transparent 55%);
        }
        .features-section .sec-title{color:#fff;margin-bottom:56px}
        .features-section .sec-title em{color:var(--gold2)}
        .features-section .sec-label{color:rgba(255,255,255,.35)}
        .features-section .sec-label::before{background:rgba(255,255,255,.2)}

        .feat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:2px;position:relative;z-index:1}
        .feat-item{
            padding:40px;border:1px solid rgba(255,255,255,.05);
            transition:background .3s;position:relative;overflow:hidden;
        }
        .feat-item::before{
            content:'';position:absolute;inset:0;
            background:radial-gradient(circle at var(--mx,50%) var(--my,50%),rgba(201,168,76,.09) 0%,transparent 65%);
            opacity:0;transition:opacity .3s;
        }
        .feat-item:hover::before{opacity:1}
        .feat-item:hover{background:rgba(255,255,255,.03)}
        .feat-ico{width:50px;height:50px;border-radius:14px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.08);display:flex;align-items:center;justify-content:center;margin-bottom:22px}
        .feat-ico svg{width:22px;height:22px;color:var(--gold)}
        .feat-item h4{font-family:'Cormorant Garamond',serif;font-size:21px;color:#fff;font-weight:600;margin-bottom:9px}
        .feat-item p{font-size:13px;color:rgba(255,255,255,.42);line-height:1.7}

        /* ══════════════ CTA ══════════════ */
        .cta-band{
            position:relative;overflow:hidden;
            min-height:480px;display:flex;align-items:center;justify-content:center;
            text-align:center;padding:80px 64px;
        }
        .cta-bg{
            position:absolute;inset:0;
            background-image:url('data:image/jpeg;base64,');
            background-size:cover;background-position:center;
            filter:brightness(.2) saturate(.6);
        }
        .cta-overlay{
            position:absolute;inset:0;
            background:linear-gradient(135deg,rgba(17,59,38,.88) 0%,rgba(46,125,50,.75) 100%);
        }
        .cta-content{position:relative;z-index:2;max-width:640px}
        .cta-content .sec-label{justify-content:center;color:rgba(255,255,255,.4)}
        .cta-content .sec-label::before{background:rgba(255,255,255,.2)}
        .cta-content h2{font-family:'Cormorant Garamond',serif;font-size:clamp(36px,5vw,60px);color:#fff;font-weight:700;line-height:1.1;margin-bottom:16px}
        .cta-content h2 em{font-style:italic;color:var(--gold2)}
        .cta-content p{font-size:15px;color:rgba(255,255,255,.5);line-height:1.7;margin-bottom:44px}
        .cta-btns{display:flex;align-items:center;justify-content:center;gap:14px;flex-wrap:wrap}
        .cta-btns .btn-hp{font-family:'Outfit',sans-serif}

        /* ══════════════ FOOTER ══════════════ */
        footer{background:var(--ink);padding:52px 64px;display:grid;grid-template-columns:1.5fr 1fr 1fr;gap:40px;border-top:1px solid rgba(255,255,255,.05)}
        .footer-brand .fb-logo{display:flex;align-items:center;gap:12px;margin-bottom:16px}
        .footer-brand .fb-logo .fl-img{width:44px;height:44px;border-radius:50%;overflow:hidden;border:1.5px solid rgba(201,168,76,.3)}
        .footer-brand .fb-logo .fl-img img{width:100%;height:100%;object-fit:cover}
        .footer-brand .fb-logo h3{font-family:'Cormorant Garamond',serif;font-size:16px;color:#fff;font-weight:600}
        .footer-brand .fb-logo span{font-size:10px;color:rgba(255,255,255,.3);letter-spacing:.1em;text-transform:uppercase;display:block}
        .footer-brand p{font-size:13px;color:rgba(255,255,255,.3);line-height:1.7}
        .footer-col h4{font-size:11px;font-weight:600;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.4);margin-bottom:16px}
        .footer-col a{display:block;font-size:13px;color:rgba(255,255,255,.35);text-decoration:none;margin-bottom:10px;transition:color .25s}
        .footer-col a:hover{color:var(--gold2)}
        .footer-bottom{grid-column:1/-1;border-top:1px solid rgba(255,255,255,.06);padding-top:28px;display:flex;align-items:center;justify-content:space-between}
        .footer-bottom span{font-size:12px;color:rgba(255,255,255,.2);letter-spacing:.06em}
        .footer-ent-badges{display:flex;gap:16px}
        .feb{display:flex;align-items:center;gap:6px;font-size:11px;color:rgba(255,255,255,.25)}
        .feb .dot{width:7px;height:7px;border-radius:50%}
        .dot-g{background:var(--green3)}
        .dot-b{background:var(--brown)}
        .dot-c{background:var(--ctd2)}

        @keyframes fadeUp{from{opacity:0;transform:translateY(28px)}to{opacity:1;transform:translateY(0)}}
        .reveal{opacity:0;transform:translateY(32px);transition:opacity .7s var(--ease),transform .7s var(--ease)}
        .reveal.in{opacity:1;transform:translateY(0)}
        .d1{transition-delay:.1s}.d2{transition-delay:.2s}.d3{transition-delay:.3s}

        @media(max-width:960px){
            nav{padding:16px 24px} nav.scrolled{padding:12px 24px}
            .nav-links{display:none}
            .hero-content{padding:100px 24px 60px}
            .hero-panel-labels{display:none}
            .stats-band{grid-template-columns:repeat(2,1fr)}
            .entities-section{padding:70px 24px}
            .ent-grid{grid-template-columns:1fr}
            .auth-section{grid-template-columns:1fr}
            .auth-signin,.auth-register{min-height:460px}
            .features-section{padding:70px 24px}
            .feat-grid{grid-template-columns:1fr}
            .cta-band{padding:60px 24px}
            footer{grid-template-columns:1fr;padding:40px 24px}
            .footer-bottom{flex-direction:column;gap:12px}
        }
    </style>
</head>
