<script>
    // Custom cursor
    const cur=document.getElementById('cur'),ring=document.getElementById('curRing');
    let mx=0,my=0,rx=0,ry=0;
    document.addEventListener('mousemove',e=>{
        mx=e.clientX;my=e.clientY;
        cur.style.left=mx+'px';cur.style.top=my+'px';
    });
    (function loop(){
        rx+=(mx-rx)*.1;ry+=(my-ry)*.1;
        ring.style.left=rx+'px';ring.style.top=ry+'px';
        requestAnimationFrame(loop);
    })();

    // Nav scroll
    window.addEventListener('scroll',()=>{
        document.getElementById('nav').classList.toggle('scrolled',scrollY>60);
    });

    // Reveal
    const obs=new IntersectionObserver(entries=>{
        entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('in')});
    },{threshold:.1});
    document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));

    // Feature spotlight
    document.querySelectorAll('.feat-item').forEach(item=>{
        item.addEventListener('mousemove',e=>{
            const r=item.getBoundingClientRect();
            item.style.setProperty('--mx',((e.clientX-r.left)/r.width*100).toFixed(1)+'%');
            item.style.setProperty('--my',((e.clientY-r.top)/r.height*100).toFixed(1)+'%');
        });
    });

    // Stat counters
    const statsObs=new IntersectionObserver(entries=>{
        entries.forEach(e=>{
            if(!e.isIntersecting) return;
            document.querySelectorAll('[data-target]').forEach(el=>{
                const target=parseInt(el.dataset.target);
                const suffix=el.dataset.suffix;
                let v=0; const step=target/60;
                const iv=setInterval(()=>{
                    v=Math.min(v+step,target);
                    el.innerHTML=Math.floor(v)+'<sup>'+suffix+'</sup>';
                    if(v>=target)clearInterval(iv);
                },16);
            });
            statsObs.disconnect();
        });
    },{threshold:.5});
    const firstStat=document.querySelector('.stat-item');
    if(firstStat) statsObs.observe(firstStat);
</script>
</body>
</html>